// src/components/EmpresaCard.js

import React from 'react';
import { motion } from 'framer-motion';

// Este componente recibe la empresa y la función onClick
const EmpresaCard = ({ empresa, onClick, isGrid }) => {
    
    // Clases condicionales para el layout de la imagen y el contenedor
    // La vista vertical no necesita 'flex-row' en la card, pero la vista de lista sí (para que el contenido quede al lado de la imagen)
    const cardLayoutClasses = isGrid 
        ? "flex-col" // Vista Grid: logo arriba, texto abajo
        : "flex-col sm:flex-row"; // Vista Lista: logo a la izquierda, texto a la derecha (en pantallas sm+)

    const imageContainerClasses = isGrid 
        ? "h-32 w-full flex-shrink-0" // Vista Grid: Imagen grande arriba
        : "h-32 w-full sm:w-48 flex-shrink-0"; // Vista Lista: Imagen más pequeña a la izquierda

    return (
        <motion.div
            className={`relative bg-white rounded-lg shadow-md hover:shadow-lg transition-all duration-300 overflow-hidden cursor-pointer flex ${cardLayoutClasses}`}
            whileHover={{ scale: 1.02 }}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            onClick={() => onClick(empresa)}
        >
            {/* Contenedor de la Imagen */}
            <div className={`relative ${imageContainerClasses}`}>
                <img
                    src={empresa.imagen}
                    alt={`Logo de ${empresa.nombre}`}
                    className="absolute inset-0 w-full h-full object-cover"
                />
                <div className="absolute inset-0 bg-black bg-opacity-40 flex items-center justify-center">
                    <h3 className="text-white text-lg font-bold text-center p-2">
                        {empresa.nombre}
                    </h3>
                </div>
            </div>
            {/* Contenido de la Tarjeta */}
            <div className="p-4 flex-grow">
                <p className="text-sm text-gray-600">{empresa.rubro}</p>
                <p className="text-sm text-gray-500">{empresa.departamento}</p>
            </div>
        </motion.div>
    );
};

export default EmpresaCard;
